INSERT INTO bpm_concepts
  (id, source_tool, source_concept, helix_equiv, helix_node_type,
   description, example, confidence, notes, created_at)
SELECT UUID(), t.c1, t.c2, t.c3, t.c4, t.c5, t.c6, t.c7, t.c8, NOW()
FROM (
