  UNION ALL SELECT 'pega', 'Assignment shape',  'user_task step',    'step',          'Work assigned to a human operator. The operator opens it, acts on it, and submits.',                     'ReviewAssignment → user_task step: review',             'exact',   NULL
  UNION ALL SELECT 'pega', 'Approval shape',    'approval step',     'step',          'A yes/no decision point. Approver sees context and approves or rejects.',                                'ManagerApproval → approval step',                       'exact',   NULL
