  UNION ALL SELECT 'pega', 'Spin-off case',     'child case',        'case_type',     'Creates a new case instance from within a running case.',                                               'SpinOffPayment → child case_type: payment',             'close',   NULL
  UNION ALL SELECT 'pega', 'Section',           'form section',      'form',          'A named group of fields in a Pega form. Maps directly to a FormDefinition section.',                   'ClaimantSection → section in Claim Form',               'exact',   NULL
  UNION ALL SELECT 'pega', 'Property',          'form field',        'field',         'A single data field. Maps to a field in a FormDefinition section.',                                    'claimAmount property → currency field: claim_amount',   'exact',   NULL
