  UNION ALL SELECT 'pega', 'Harness',           'portal page',       NULL,            'The full-page UI container. Helix uses Portal.tsx for customer-facing and Studio for operators.',       'WorkHarness → Studio CaseManager module',               'close',   'UI layout is not converted — rebuilt in React'
  UNION ALL SELECT 'pega', 'Clipboard',         'case data (JSONB)', NULL,            'In-memory data model for a running case. In Helix, case data lives in case_instances.data JSONB.',     'pyWorkPage.ClaimAmount → case.data.claim_amount',       'close',   NULL
  UNION ALL SELECT 'pega', 'Data Page',         'API endpoint',      'endpoint',      'Cached data source. In Helix, data is fetched from API endpoints with caching at the HTTP layer.',     'D_ClaimList data page → GET /api/v1/cases endpoint',   'partial', 'Caching strategy differs'
  UNION ALL SELECT 'pega', 'Access Group',      'access_group',      'access_group',  'Groups operators and defines what they can see and do. Direct equivalent in Helix.',                  'ClaimsAdjusters → access_group: claims_adjusters',     'exact',   NULL
  UNION ALL SELECT 'pega', 'Operator',          'operator / user',   NULL,            'A person who uses the Pega application. Maps to Helix operator with access group memberships.',       'adjuster@example.com → operator in Claims Adjusters',  'exact',   NULL
  UNION ALL SELECT 'pega', 'Worklist',          'Work Center queue', NULL,            'Personal queue of assignments for an operator. Helix equivalent is the Work Center module.',          'Worklist → /work-center',                               'exact',   NULL
  UNION ALL SELECT 'pega', 'Work Queue',        'queue',             NULL,            'Shared queue that multiple operators can pull from. Helix queues are defined per access group.',       'ClaimsQueue → queue in Claims Adjusters access group',  'exact',   NULL
