  UNION ALL SELECT 'appian', 'Process Model',        'case_type',         'case_type',  'Top-level Appian process. Maps to a Helix case_type.',                                                          'LoanApprovalProcess → case_type: loan_approval',      'close',   NULL
  UNION ALL SELECT 'appian', 'User Input Task',      'user_task step',    'step',       'Human task in Appian. Direct equivalent to Helix user_task step.',                                              'ReviewApplicationTask → user_task step',              'exact',   NULL
  UNION ALL SELECT 'appian', 'Automated Task',       'automated step',    'step',       'System-executed task. Maps to Helix automated step.',                                                            'SendEmailTask → automated step',                      'exact',   NULL
