  UNION ALL SELECT 'appian', 'Interface',            'form',              'form',       'Appian UI form definition. Maps to Helix FormDefinition JSON.',                                                  'LoanApplicationInterface → FormDefinition: loan_app',  'close',   'Appian SAIL expressions need re-expression'
  UNION ALL SELECT 'appian', 'Expression Rule',      'routing rule',      NULL,         'Reusable expression/formula. Maps to Helix routing rules or field calculated values.',                          'EligibilityRule → routing rule condition',            'close',   NULL
